    // --- ENHANCED FAILOVER: KEYS + MODELS ---
    const executeWithSmartFailover = async <T,>(
        operation: (apiKey: string, model: string) => Promise<T>, 
    ): Promise<T> => {

        // 1. Iterate through Model Hierarchy (Pro -> Flash -> Flash Lite)
        for (let mIndex = 0; mIndex < MODEL_HIERARCHY.length; mIndex++) {
            const currentModel = MODEL_HIERARCHY[mIndex];

            try {
                // 2. Perform Key Failover for THIS model
                return await executeWithApiKeyFailover(async (key) => {
                    return await operation(key, currentModel);
                });
            } catch (error: any) {
                // If ALL keys failed for this model...
                if (error.message === "ALL_KEYS_EXHAUSTED") {
                    // If we have more models to try, Reset keys and continue to next model loop
                    if (mIndex < MODEL_HIERARCHY.length - 1) {
                        const nextModel = MODEL_HIERARCHY[mIndex + 1];
                        console.warn(`[Smart Cascade] Model ${currentModel} exhausted. Downgrading to ${nextModel}...`);

                        // Notify User
                        setToastMsg(`Downgrading to lighter AI model (${nextModel}) to maintain service...`);

                        // CRITICAL: Reset 'quota_exceeded' keys so they can be tried again with the new model
                        // (Usually quota is shared, but different models consume quota at different rates)
                        setApiKeys(prev => prev.map(k => k.status === 'quota_exceeded' ? { ...k, status: 'valid' } : k));

                        continue; // Go to next model iteration
                    }
                }
                // If it's the last model or a different error, throw it up
                throw error;
            }
        }

        throw new Error("ALL_RESOURCES_EXHAUSTED");
    };

    const executeWithApiKeyFailover = async <T,>(
        operation: (apiKey: string) => Promise<T>, 
        attemptedKeys: string[] = []
    ): Promise<T> => {
        const availableKeys = apiKeys.filter(k => 
            k.status !== 'invalid' && 
            k.status !== 'quota_exceeded' && 
            !attemptedKeys.includes(k.id) 
        );

        availableKeys.sort((a, b) => a.latency - b.latency);

        let candidateKey: ApiKeyProfile | undefined = undefined;

        const activeCandidate = availableKeys.find(k => k.id === activeKeyId);
        if (activeCandidate) {
            candidateKey = activeCandidate;
        } else if (availableKeys.length > 0) {
            candidateKey = availableKeys[0];
        }

        if (!candidateKey) {
             const desperateKeys = apiKeys.filter(k => 
                k.status !== 'invalid' && 
                !attemptedKeys.includes(k.id)
            );
            if (desperateKeys.length > 0) {
                candidateKey = desperateKeys[0];
            }
        }

        if (!candidateKey) {
            throw new Error("ALL_KEYS_EXHAUSTED");
        }

        if (candidateKey.id !== activeKeyId) {
            setActiveKeyId(candidateKey.id);
        }

        try {
            return await operation(candidateKey.key);
        } catch (error: any) {
            const msg = error.message?.toLowerCase() || "";
            const isApiError = msg.includes("429") || msg.includes("quota") || msg.includes("resource exhausted") || (msg.includes("403") && !msg.includes("api key not valid"));

            if (isApiError) {
                setApiKeys(prev => prev.map(k => k.id === candidateKey!.id ? { ...k, status: 'quota_exceeded' } : k));
                return await executeWithApiKeyFailover(operation, [...attemptedKeys, candidateKey.id]);
            }
            if (msg.includes("key not valid") || msg.includes("api key")) {
                 setApiKeys(prev => prev.map(k => k.id === candidateKey!.id ? { ...k, status: 'invalid' } : k));
                 return await executeWithApiKeyFailover(operation, [...attemptedKeys, candidateKey.id]);
            }

            throw error;
        }
    };

