                                                    else if (result.status === 'NC_MAJOR') { bgColor = 'bg-red-600'; textColor = 'text-white'; }
                                                    else if (result.status === 'NC_MINOR') { bgColor = 'bg-orange-500'; textColor = 'text-white'; }
