                                                    <div className="bg-gray-50 dark:bg-slate-950/50 p-2 rounded-lg border border-gray-100 dark:border-slate-800 mt-1">
                                                        <span className="text-[10px] text-slate-400 font-bold uppercase block mb-1">Evidence:</span>
