    const handleUpdateStandard = (updated: Standard) => {
        setCustomStandards(prev => ({ ...prev, [standardKey]: updated }));
    };

    const handleResetStandard = (key: string) => {
        setCustomStandards(prev => {
            const next = { ...prev };
