                } catch (innerError: any) {
                    if (innerError.message === "ALL_RESOURCES_EXHAUSTED" || innerError.message === "ALL_KEYS_EXHAUSTED") {
                        throw innerError; 
                    }
                    console.error(`Failed to analyze clause ${clause.code}`, innerError);
