export const Icon = ({ name, size = 18, className = "" }: { name: string; size?: number; className?: string }) => {
    const icon = ICONS[name] || ICONS.Default;
    return (
        <span className={`inline-flex items-center justify-center ${className}`} style={{ width: size, height: size }}>
            {React.isValidElement(icon) ? React.cloneElement(icon as React.ReactElement, { width: size, height: size }) : icon}
        </span>
    );
};

export const IconSelect = ({ icon, iconColor, value, onChange, options, defaultText }: any) => (
    <div className="relative">
        {icon && <div className={`absolute left-3 top-2.5 ${iconColor}`}><Icon name={icon} size={14}/></div>}
        <select 
            value={value} 
            onChange={onChange}
            className={`w-full bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 text-slate-900 dark:text-white text-xs rounded-xl px-3 py-2.5 outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all appearance-none ${icon ? 'pl-9' : ''}`}
        >
            <option value="" disabled>{defaultText}</option>
            {options.map((o: any) => <option key={o.value} value={o.value}>{o.label}</option>)}
        </select>
        <div className="absolute right-3 top-3 pointer-events-none text-slate-400">
            <Icon name="ChevronDown" size={12}/>
        </div>
    </div>
);

export const IconInput = ({ icon, iconColor, placeholder, value, onChange, className = "" }: any) => (
    <div className={`relative ${className}`}>
        {icon && <div className={`absolute left-3 top-2.5 ${iconColor}`}><Icon name={icon} size={14}/></div>}
        <input 
            type="text" 
            placeholder={placeholder}
            value={value}
            onChange={onChange}
            className={`w-full bg-gray-50 dark:bg-slate-800 border border-gray-200 dark:border-slate-700 text-slate-900 dark:text-white text-xs rounded-xl px-3 py-2.5 outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all placeholder-slate-400 ${icon ? 'pl-9' : ''}`}
        />
    </div>
);

export const Modal = ({ isOpen, title, onClose, children }: any) => {
    if (!isOpen) return null;
    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200" onClick={onClose}>
            <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] border border-gray-100 dark:border-slate-800 animate-in zoom-in-95 duration-200" onClick={e => e.stopPropagation()}>
                <div className="flex items-center justify-between p-5 border-b border-gray-100 dark:border-slate-800">
                    <h3 className="text-lg font-black text-slate-900 dark:text-white tracking-tight">{title}</h3>
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-400 hover:text-red-500 transition-colors">
                        <Icon name="X" size={18}/>
                    </button>
                </div>
                <div className="p-6 overflow-y-auto custom-scrollbar">
                    {children}
                </div>
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import { STANDARDS_DATA } from './constants';
import { AuditInfo, StandardsData, Standard } from './types';
import { Icon } from './components/UI';

const FontSizeController = ({ fontSizeScale, adjustFontSize }: { fontSizeScale: number, adjustFontSize: (dir: 'increase' | 'decrease') => void }) => (
    <div className="flex items-center bg-gray-100 dark:bg-slate-800 rounded-lg p-1">
        <button onClick={() => adjustFontSize('decrease')} className="p-1.5 hover:bg-white dark:hover:bg-slate-700 rounded-md text-slate-500 transition-colors">
            <span className="text-xs font-bold">A-</span>
        </button>
        <span className="px-2 text-xs font-mono text-slate-400">{Math.round(fontSizeScale * 100)}%</span>
        <button onClick={() => adjustFontSize('increase')} className="p-1.5 hover:bg-white dark:hover:bg-slate-700 rounded-md text-slate-500 transition-colors">
            <span className="text-xs font-bold">A+</span>
        </button>
    </div>
);

function App() {
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(360);
    const [standards, setStandards] = useState<StandardsData>(STANDARDS_DATA);
    const [standardKey, setStandardKey] = useState<string>(Object.keys(STANDARDS_DATA)[0] || "");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({
        company: "",
        smo: "",
        department: "",
        interviewee: "",
        auditor: "",
        type: "Internal"
    });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);
    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);
    const [showReleaseNotes, setShowReleaseNotes] = useState(false);

    const handleAddNewStandard = () => {
        alert("Feature to add new standard coming soon!");
    };

    const handleUpdateStandard = (std: Standard) => {
        setStandards(prev => ({
            ...prev,
            [standardKey]: std
        }));
    };

    const handleResetStandard = (key: string) => {
        if (STANDARDS_DATA[key]) {
             setStandards(prev => ({
                ...prev,
                [key]: STANDARDS_DATA[key]
            }));
        }
    };

    return (
        <div className="flex h-screen bg-white dark:bg-slate-950 overflow-hidden font-sans text-slate-900 dark:text-slate-100" style={{ fontSize: `${fontSizeScale}rem` }}>
            <Sidebar 
                isOpen={isSidebarOpen}
                width={sidebarWidth}
                setWidth={setSidebarWidth}
                standards={standards}
                standardKey={standardKey}
                setStandardKey={setStandardKey}
                auditInfo={auditInfo}
                setAuditInfo={setAuditInfo}
                selectedClauses={selectedClauses}
                setSelectedClauses={setSelectedClauses}
                onAddNewStandard={handleAddNewStandard}
                onUpdateStandard={handleUpdateStandard}
                onResetStandard={handleResetStandard}
            />

            <div className="flex-1 flex flex-col min-w-0 relative">
                 {/* Header / Top Bar */}
                 <div className="h-14 border-b border-gray-100 dark:border-slate-800 flex items-center justify-between px-4 bg-white dark:bg-slate-900 shrink-0">
                    <div className="flex items-center gap-4">
                        <button 
                            onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                            className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-500 transition-colors"
                        >
                            <Icon name={isSidebarOpen ? "SidebarClose" : "SidebarOpen"} size={20} className={!isSidebarOpen ? "rotate-180" : ""} /> 
                        </button>
                        <h1 className="text-lg font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-cyan-500">ISO Audit Pro</h1>
                    </div>

                    <div className="flex items-center gap-2">
                        <button 
                            onClick={() => setIsCmdPaletteOpen(true)} 
                            className="p-2 rounded-lg text-slate-600 hover:text-indigo-600 dark:text-slate-400 dark:hover:text-indigo-400 hover:bg-gray-100 dark:hover:bg-slate-800 transition-all active:scale-95 group"
                            title="Open Command Palette (Ctrl+K)"
                        >
                            <div className="group-hover:rotate-12 transition-transform duration-300">
                                <Icon name="Command" size={20}/>
                            </div>
                        </button>

                        <div className="hidden lg:block">
                            <FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={(dir: 'increase' | 'decrease') => setFontSizeScale(prev => dir === 'increase' ? Math.min(prev + 0.1, 1.3) : Math.max(prev - 0.1, 0.8))} />
                        </div>

                        <button onClick={() => setShowReleaseNotes(true)} className="p-2 text-slate-400 hover:text-indigo-500 transition-colors">
                            <Icon name="Info" size={20} />
                        </button>
                    </div>
                 </div>

                 {/* Main Content Area */}
                 <div className="flex-1 overflow-auto p-6 bg-gray-50/50 dark:bg-slate-950/50">
                    <div className="max-w-4xl mx-auto">
                        <div className="bg-white dark:bg-slate-900 rounded-2xl p-8 shadow-sm border border-gray-100 dark:border-slate-800 text-center py-20">
                            <div className="w-16 h-16 bg-indigo-50 dark:bg-indigo-900/20 rounded-full flex items-center justify-center mx-auto mb-6 text-indigo-500">
                                <Icon name="LayoutList" size={32} />
                            </div>
                            <h2 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">Ready to Audit</h2>
                            <p className="text-slate-500 dark:text-slate-400 max-w-md mx-auto">
                                Select a standard from the sidebar, configure your audit details, and start selecting clauses to generate your report.
                            </p>
                        </div>
                    </div>
                 </div>
            </div>

            <ReleaseNotesModal isOpen={showReleaseNotes} onClose={() => setShowReleaseNotes(false)} />

            {isCmdPaletteOpen && (
                <div className="fixed inset-0 z-[100] flex items-start justify-center pt-20 bg-black/20 backdrop-blur-sm" onClick={() => setIsCmdPaletteOpen(false)}>
                     <div className="bg-white dark:bg-slate-900 w-full max-w-xl rounded-xl shadow-2xl overflow-hidden border border-gray-200 dark:border-slate-700 animate-in slide-in-from-top-4" onClick={e => e.stopPropagation()}>
                        <div className="p-4 border-b border-gray-100 dark:border-slate-800 flex items-center gap-3">
                            <Icon name="Search" size={18} className="text-slate-400"/>
                            <input autoFocus placeholder="Type a command or search..." className="flex-1 bg-transparent outline-none text-sm" />
                            <span className="text-xs font-mono text-slate-400 border border-slate-200 dark:border-slate-700 px-1.5 py-0.5 rounded">ESC</span>
                        </div>
                        <div className="p-2">
                            <div className="p-2 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg cursor-pointer text-sm flex items-center gap-3 text-slate-600 dark:text-slate-300">
