                                        <span className="text-xs text-slate-500 mb-2">{exportState.error}</span>

                                        {/* INLINE KEY INPUT FOR IMMEDIATE RESUME */}
                                        <div className="w-full mt-2 animate-in fade-in slide-in-from-bottom-2">
                                            <input 
                                                type="text" 
