                                        <p className="text-2xl font-black text-indigo-600 dark:text-white">
                                            {exportState.processedChunksCount + 1} <span className="text-base text-slate-400 font-normal">/ {exportState.totalChunks}</span>
                                        </p>
                                    </div>
