export const Icon = ({ name, size = 16, className = "" }: { name: string, size?: number, className?: string }) => {
    const icon = ICONS[name] || <span title={name}>?</span>;
    return (
        <span className={`inline-flex items-center justify-center ${className}`} style={{ width: size, height: size }}>
            {React.isValidElement(icon) ? React.cloneElement(icon as React.ReactElement, { width: size, height: size }) : icon}
        </span>
    );
};

export const IconSelect = ({ icon, iconColor, value, onChange, options, defaultText }: any) => (
    <div className="relative">
        <div className={`absolute left-3 top-2.5 pointer-events-none ${iconColor}`}>
            <Icon name={icon} size={14} />
        </div>
        <select 
            value={value} 
            onChange={onChange}
            className="w-full pl-9 pr-8 py-2 text-xs bg-gray-100 dark:bg-slate-800 rounded-xl outline-none text-slate-800 dark:text-slate-200 appearance-none border border-transparent focus:border-indigo-100 cursor-pointer transition-colors hover:bg-gray-200 dark:hover:bg-slate-700"
        >
            <option value="" disabled>{defaultText}</option>
            {options.map((opt: any) => (
                <option key={opt.value} value={opt.value}>{opt.label}</option>
            ))}
        </select>
        <div className="absolute right-3 top-2.5 text-slate-400 pointer-events-none">
            <Icon name="ChevronDown" size={12} />
        </div>
    </div>
);

export const IconInput = ({ icon, iconColor, placeholder, value, onChange, className = "" }: any) => (
    <div className={`relative ${className}`}>
        <div className={`absolute left-3 top-2.5 pointer-events-none ${iconColor}`}>
            <Icon name={icon} size={14} />
        </div>
        <input 
            type="text"
            value={value}
            onChange={onChange}
            placeholder={placeholder}
            className="w-full pl-9 pr-3 py-2 text-xs bg-gray-100 dark:bg-slate-800 rounded-xl outline-none text-slate-800 dark:text-slate-200 placeholder-gray-400 border border-transparent focus:border-indigo-100 transition-colors focus:bg-white dark:focus:bg-slate-900"
        />
    </div>
);

export const Modal = ({ isOpen, title, onClose, children }: any) => {
    if (!isOpen) return null;
    return (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center p-4 backdrop-blur-sm animate-in fade-in duration-200" onClick={onClose}>
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-2xl w-full max-w-lg border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
                <div className="flex items-center justify-between p-4 border-b border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-800/50 shrink-0">
                    <h3 className="font-bold text-slate-800 dark:text-white">{title}</h3>
                    <button onClick={onClose} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors p-1 rounded-full hover:bg-gray-200 dark:hover:bg-slate-700">
                        <Icon name="X" size={18} />
                    </button>
                </div>
                <div className="p-4 overflow-y-auto custom-scrollbar">
                    {children}
                </div>
            </div>
        </div>
    );
};

export const FontSizeController = ({ fontSizeScale, adjustFontSize }: { fontSizeScale: number, adjustFontSize: (dir: 'increase' | 'decrease') => void }) => {
    return (
        <div className="flex items-center bg-gray-100 dark:bg-slate-800 rounded-lg p-1 border border-transparent hover:border-gray-200 dark:hover:border-slate-700 transition-colors">
            <button 
                onClick={() => adjustFontSize('decrease')} 
                className="p-1 hover:bg-white dark:hover:bg-slate-700 rounded text-xs text-slate-600 dark:text-slate-300 font-bold w-6 h-6 flex items-center justify-center"
                title="Decrease Font Size"
            >
                A-
            </button>
            <span className="mx-2 text-[10px] font-mono text-slate-400">{Math.round(fontSizeScale * 100)}%</span>
            <button 
                onClick={() => adjustFontSize('increase')} 
                className="p-1 hover:bg-white dark:hover:bg-slate-700 rounded text-xs text-slate-600 dark:text-slate-300 font-bold w-6 h-6 flex items-center justify-center"
                title="Increase Font Size"
            >
                A+
            </button>
        </div>
    )
};

import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import { STANDARDS_DATA, INITIAL_EVIDENCE } from './constants';
import { StandardsData, AuditInfo, Standard } from './types';
import { Icon, FontSizeController } from './components/UI';

const App = () => {
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(390);
    const [standardKey, setStandardKey] = useState("ISO 9001:2015");
    const [standards, setStandards] = useState<StandardsData>(STANDARDS_DATA);
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({
        company: "", smo: "", department: "", interviewee: "", auditor: "", type: "Internal"
    });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // Header states
    const [isCmdPaletteOpen, setIsCmdPaletteOpen] = useState(false);
    const [fontSizeScale, setFontSizeScale] = useState(1);
    const [showReleaseNotes, setShowReleaseNotes] = useState(false);

    // Handlers
    const handleAddNewStandard = () => { 
        // Logic for adding new standard (placeholder)
        const name = prompt("Enter Name of New Standard:");
        if (name) {
            const key = name.replace(/\s+/g, '_').toUpperCase();
            setStandards(prev => ({
                ...prev,
                [key]: { name, description: "Custom Standard", groups: [] }
            }));
            setStandardKey(key);
        }
    };

    const handleUpdateStandard = (std: Standard) => { 
        setStandards(prev => ({...prev, [standardKey]: std}));
    };

    const handleResetStandard = (key: string) => {
        if(STANDARDS_DATA[key]) {
             setStandards(prev => ({...prev, [key]: JSON.parse(JSON.stringify(STANDARDS_DATA[key]))}));
        }
    };

    return (
        <div className="flex h-screen w-full bg-gray-50 dark:bg-slate-950 text-slate-900 dark:text-slate-100 font-sans overflow-hidden transition-all duration-200" style={{fontSize: `${fontSizeScale}rem`}}>
            <Sidebar 
                isOpen={isSidebarOpen}
                width={sidebarWidth}
                setWidth={setSidebarWidth}
                standards={standards}
                standardKey={standardKey}
                setStandardKey={setStandardKey}
                auditInfo={auditInfo}
                setAuditInfo={setAuditInfo}
                selectedClauses={selectedClauses}
                setSelectedClauses={setSelectedClauses}
                onAddNewStandard={handleAddNewStandard}
                onUpdateStandard={handleUpdateStandard}
                onResetStandard={handleResetStandard}
            />

            <div className="flex-1 flex flex-col min-w-0 relative">
                {/* Header Area */}
                <header className="h-16 border-b border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 flex items-center justify-between px-4 shrink-0 shadow-sm z-10">
                   <div className="flex items-center gap-3">
                        <button 
                            onClick={() => setIsSidebarOpen(!isSidebarOpen)} 
                            className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-500 transition-colors"
                            title={isSidebarOpen ? "Close Sidebar" : "Open Sidebar"}
                        >
                            <Icon name={isSidebarOpen ? "Layout" : "Layout"} size={20} />
                        </button>
                        <h1 className="font-bold text-lg hidden md:block bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-cyan-500">ISO Audit Pro</h1>
                   </div>

                   {/* Right Side Actions */}
                   <div className="flex items-center gap-2">
                        {/* COMMAND PALETTE TRIGGER (Visible on Mobile & Desktop) */}
                        <button 
                            onClick={() => setIsCmdPaletteOpen(true)} 
                            className="p-2 rounded-lg text-slate-500 hover:text-indigo-600 dark:text-slate-400 dark:hover:text-indigo-400 hover:bg-gray-100 dark:hover:bg-slate-800 transition-all active:scale-95"
                            title="Open Command Palette (Ctrl+K)"
                        >
                            <Icon name="Layers" size={20}/>
                        </button>

                        <div className="hidden lg:block">
                            <FontSizeController fontSizeScale={fontSizeScale} adjustFontSize={(dir: any) => setFontSizeScale(prev => dir === 'increase' ? Math.min(prev + 0.1, 1.3) : Math.max(prev - 0.1, 0.8))} />
                        </div>

                        <button onClick={() => setShowReleaseNotes(true)} className="ml-2 p-2 text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 rounded-full transition-colors" title="Release Notes">
                             <Icon name="Info" size={20} />
                        </button>
                    </div>
                </header>

                {/* Main Content Area Placeholder */}
                <main className="flex-1 overflow-auto p-6 scroll-smooth">
                    {selectedClauses.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-slate-400 animate-in fade-in duration-500">
