                                        Analyzing <strong className="text-indigo-600 dark:text-indigo-400">{selectedClauses.length}</strong> controls for <strong className="text-slate-800 dark:text-slate-200">{auditInfo.company || 'New Audit'}</strong>
                                    </p>
                                </div>
                                <div className="flex gap-2">
                                     {/* Action buttons would go here */}
                                </div>
                            </div>

                            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                                <div className="lg:col-span-2 space-y-6">
