                                        <div className="space-y-3">
                                            <div className="flex justify-between items-center p-3 bg-gray-50 dark:bg-slate-800/50 rounded-lg">
                                                <span className="text-sm">Clauses Selected</span>
                                                <span className="font-bold text-indigo-600">{selectedClauses.length}</span>
                                            </div>
                                            <div className="flex justify-between items-center p-3 bg-gray-50 dark:bg-slate-800/50 rounded-lg">
                                                <span className="text-sm">Audit Type</span>
                                                <span className="font-bold text-slate-700 dark:text-slate-300">{auditInfo.type}</span>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </main>
            </div>

            <ReleaseNotesModal isOpen={showReleaseNotes} onClose={() => setShowReleaseNotes(false)} />

            {/* Command Palette Placeholder */}
            {isCmdPaletteOpen && (
                <div className="fixed inset-0 bg-black/50 z-[100] flex items-start justify-center pt-24 backdrop-blur-sm animate-in fade-in duration-200" onClick={() => setIsCmdPaletteOpen(false)}>
                    <div className="bg-white dark:bg-slate-900 p-2 rounded-xl shadow-2xl w-full max-w-xl border border-gray-200 dark:border-slate-700" onClick={e => e.stopPropagation()}>
                        <div className="p-3 border-b border-gray-100 dark:border-slate-800 flex items-center gap-3">
                            <Icon name="Search" size={18} className="text-slate-400"/>
                            <input autoFocus className="w-full bg-transparent outline-none text-sm font-medium" placeholder="Type a command or search..."/>
                            <div className="px-1.5 py-0.5 rounded border border-gray-200 dark:border-slate-700 text-[10px] font-mono text-slate-400">ESC</div>
                        </div>
                        <div className="p-2 text-center text-xs text-slate-400 py-8">
                            No commands found.
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default App;
